## File: `src/__tests__/manifest-schema.test.ts`

Write tests covering:

1. **Valid manifest**: All fields present, parses successfully
2. **Minimal manifest**: Only required fields (`id`, `name`, `version`), parses successfully
3. **Invalid ID**: Uppercase letters rejected, spaces rejected, empty string rejected, must start with alphanumeric
4. **Invalid version**: Non-semver string rejected (e.g., `"v1"`, `"latest"`)
5. **Missing required fields**: `id`, `name`, `version` each cause failure when omitted
6. **Optional fields**: `description`, `author`, `minHostVersion`, `contributions`, `permissions` all optional
7. **Contributions record**: `{ "dashboard.sections": true }` parses correctly
8. **Permissions array**: `["storage", "network"]` parses correctly

Example test structure:

```typescript
import { describe, it, expect } from 'vitest';
import { ExtensionManifestSchema } from '../manifest-schema.js';

describe('ExtensionManifestSchema', () => {
  it('parses a complete valid manifest', () => {
    const manifest = {
      id: 'github-prs',
      name: 'GitHub PR Dashboard',
      version: '1.0.0',
      description: 'Shows pending PR reviews',
      author: 'dorkbot',
      minHostVersion: '0.1.0',
      contributions: { 'dashboard.sections': true },
      permissions: ['storage'],
    };
    const result = ExtensionManifestSchema.safeParse(manifest);
    expect(result.success).toBe(true);
  });

  it('parses a minimal manifest (only required fields)', () => {
    const result = ExtensionManifestSchema.safeParse({
      id: 'hello-world',
      name: 'Hello World',
      version: '0.1.0',
    });
    expect(result.success).toBe(true);
  });

  it('rejects an ID with uppercase letters', () => {
    const result = ExtensionManifestSchema.safeParse({
      id: 'MyPlugin',
      name: 'My Plugin',
      version: '1.0.0',
    });
    expect(result.success).toBe(false);
  });

  it('rejects a non-semver version string', () => {
    const result = ExtensionManifestSchema.safeParse({
      id: 'test',
      name: 'Test',
      version: 'latest',
    });
    expect(result.success).toBe(false);
  });

  it('rejects when required field id is missing', () => {
    const result = ExtensionManifestSchema.safeParse({
      name: 'No ID',
      version: '1.0.0',
    });
    expect(result.success).toBe(false);
  });
});
```

