Create the `ExtensionDiscovery` service that scans filesystem paths for extension directories containing valid `extension.json` manifests.

## File: `apps/server/src/services/extensions/extension-discovery.ts`

Also create the barrel: `apps/server/src/services/extensions/index.ts`

## Constructor Dependencies

The `ExtensionDiscovery` class receives `dorkHome: string` as a required parameter (following the dork-home convention — no fallback chains).

## Discovery Algorithm

```typescript
import fs from 'fs/promises';
import path from 'path';
import { ExtensionManifestSchema } from '@dorkos/extension-api';
import type { ExtensionRecord, ExtensionManifest, ExtensionStatus } from '@dorkos/extension-api';
import { gte } from 'semver';
import { logger } from '../../lib/logger.js';

/** Host version for compatibility checking. */
const HOST_VERSION = '0.1.0'; // Source from packages/shared/src/constants.ts or root package.json

export class ExtensionDiscovery {
  private dorkHome: string;

  constructor(dorkHome: string) {
    this.dorkHome = dorkHome;
  }

  /**
   * Scan for extensions in both global and local directories.
   *
   * @param cwd - Optional current working directory for local extension scanning
   * @param enabledIds - Extension IDs that the user has enabled (from config)
   * @returns All discovered extension records, with local overriding global by ID
   */
  async discover(cwd: string | null, enabledIds: string[]): Promise<ExtensionRecord[]> {
    const globalDir = path.join(this.dorkHome, 'extensions');
    const globalRecords = await this.scanDirectory(globalDir, 'global');

    let localRecords: ExtensionRecord[] = [];
    if (cwd) {
      const localDir = path.join(cwd, '.dork', 'extensions');
      localRecords = await this.scanDirectory(localDir, 'local');
    }

    // Merge: local overrides global by extension ID
    const merged = new Map<string, ExtensionRecord>();
    for (const rec of globalRecords) {
      merged.set(rec.id, rec);
    }
    for (const rec of localRecords) {
      merged.set(rec.id, rec); // Local wins
    }

    // Apply status based on version compatibility and enabled state
    const results: ExtensionRecord[] = [];
    for (const rec of merged.values()) {
      if (rec.status === 'invalid') {
        results.push(rec);
        continue;
      }

      // Check version compatibility
      if (!this.checkCompatibility(rec.manifest)) {
        rec.status = 'incompatible';
        results.push(rec);
        continue;
      }

      // Check if enabled by user
      if (enabledIds.includes(rec.id)) {
        rec.status = 'enabled';
      } else {
        rec.status = 'disabled';
      }
      results.push(rec);
    }

    logger.info(`[Extensions] Discovered ${results.length} extension(s): ${results.map((r) => `${r.id} (${r.status})`).join(', ') || 'none'}`);
    return results;
  }

  /**
   * Scan a single directory for extension subdirectories.
   */
  private async scanDirectory(
    dir: string,
    scope: 'global' | 'local'
  ): Promise<ExtensionRecord[]> {
    try {
      await fs.access(dir);
    } catch {
      // Directory doesn't exist — not an error, just no extensions
      return [];
    }

    const entries = await fs.readdir(dir, { withFileTypes: true });
    const records: ExtensionRecord[] = [];

    for (const entry of entries) {
      if (!entry.isDirectory()) continue;

      const extDir = path.join(dir, entry.name);
      const manifestPath = path.join(extDir, 'extension.json');

      try {
        const raw = await fs.readFile(manifestPath, 'utf-8');
        const parsed = JSON.parse(raw);
        const result = ExtensionManifestSchema.safeParse(parsed);

        if (!result.success) {
          records.push({
            id: entry.name,
            manifest: parsed as ExtensionManifest,
            status: 'invalid',
            scope,
            path: extDir,
            error: {
              code: 'invalid_manifest',
              message: 'Manifest validation failed',
              details: result.error.message,
            },
            bundleReady: false,
          });
          continue;
        }

        records.push({
          id: result.data.id,
          manifest: result.data,
          status: 'discovered',
          scope,
          path: extDir,
          bundleReady: false,
        });
      } catch (err) {
        records.push({
          id: entry.name,
          manifest: { id: entry.name, name: entry.name, version: '0.0.0' },
          status: 'invalid',
          scope,
          path: extDir,
          error: {
            code: 'manifest_read_error',
            message: err instanceof Error ? err.message : 'Failed to read extension.json',
          },
          bundleReady: false,
        });
      }
    }

    return records;
  }

  /**
   * Check if the host version satisfies the extension's minimum requirement.
   */
  private checkCompatibility(manifest: ExtensionManifest): boolean {
    if (!manifest.minHostVersion) return true;
    return gte(HOST_VERSION, manifest.minHostVersion);
  }
}
```

## Test File: `apps/server/src/services/extensions/__tests__/extension-discovery.test.ts`

Write tests covering:

1. **Empty directories**: Discovery returns empty array when no extensions exist
2. **Valid global extension**: A directory with valid `extension.json` is discovered with `scope: 'global'`
3. **Valid local extension**: A directory with valid `extension.json` in `{cwd}/.dork/extensions/` has `scope: 'local'`
4. **Local overrides global**: Same extension ID in both global and local — local wins
5. **Invalid manifest**: Missing required fields produce `status: 'invalid'` with error details
6. **Missing manifest file**: Directory without `extension.json` produces `status: 'invalid'`
7. **Version incompatible**: Extension with `minHostVersion` higher than host version gets `status: 'incompatible'`
8. **Enabled extensions**: Extension ID in `enabledIds` array gets `status: 'enabled'`
9. **Disabled by default**: Extension ID NOT in `enabledIds` gets `status: 'disabled'`
10. **Non-existent directory**: Scanning a path that doesn't exist returns empty array (no error thrown)

Use `fs/promises` mocks or create temporary directories with `os.tmpdir()` for filesystem tests.

