Create the `ExtensionCompiler` service that handles TypeScript to JavaScript compilation with content-hash-based caching.

## File: `apps/server/src/services/extensions/extension-compiler.ts`

## Entry Point Resolution

```
1. Check for index.js in extension directory → if exists, use directly (pre-compiled)
2. Check for index.ts → if exists, compile with esbuild
3. Neither exists → error: 'no_entry_point'
```

## Implementation

```typescript
import { build } from 'esbuild';
import { createHash } from 'crypto';
import fs from 'fs/promises';
import path from 'path';
import { logger } from '../../lib/logger.js';
import type { ExtensionRecord } from '@dorkos/extension-api';

/** Structured compilation error written to cache as .error.json */
interface CompilationError {
  code: 'compilation_failed';
  message: string;
  errors: Array<{
    text: string;
    location?: { file: string; line: number; column: number };
  }>;
}

/** Bundle size threshold for warning log. Not a hard limit. */
const BUNDLE_SIZE_WARNING_KB = 500;

export class ExtensionCompiler {
  private cacheDir: string;

  constructor(dorkHome: string) {
    this.cacheDir = path.join(dorkHome, 'cache', 'extensions');
  }

  /**
   * Compile an extension (or return cached bundle).
   *
   * @param record - Extension record with path to source directory
   * @returns Object with `code` (compiled JS string) on success, or `error` on failure.
   *          Also returns the `sourceHash` for cache keying.
   */
  async compile(
    record: ExtensionRecord
  ): Promise<{ code: string; sourceHash: string } | { error: CompilationError; sourceHash: string }> {
    // Resolve entry point
    const jsPath = path.join(record.path, 'index.js');
    const tsPath = path.join(record.path, 'index.ts');

    let entryPath: string;
    let isPrecompiled = false;

    try {
      await fs.access(jsPath);
      entryPath = jsPath;
      isPrecompiled = true;
    } catch {
      try {
        await fs.access(tsPath);
        entryPath = tsPath;
      } catch {
        const error: CompilationError = {
          code: 'compilation_failed',
          message: 'No entry point found (index.js or index.ts)',
          errors: [{ text: 'No index.js or index.ts found in extension directory' }],
        };
        return { error, sourceHash: '' };
      }
    }

    // Read source and compute content hash
    const source = await fs.readFile(entryPath, 'utf-8');
    const sourceHash = this.computeSourceHash(source);

    // For pre-compiled JS, serve directly (still cache for consistent serving)
    if (isPrecompiled) {
      await this.ensureCacheDir();
      const cachedPath = path.join(this.cacheDir, `${record.id}.${sourceHash}.js`);
      try {
        await fs.access(cachedPath);
        const cached = await fs.readFile(cachedPath, 'utf-8');
        return { code: cached, sourceHash };
      } catch {
        await fs.writeFile(cachedPath, source, 'utf-8');
        return { code: source, sourceHash };
      }
    }

    // Check cache for compiled output
    await this.ensureCacheDir();
    const cachedJsPath = path.join(this.cacheDir, `${record.id}.${sourceHash}.js`);
    const cachedErrorPath = path.join(this.cacheDir, `${record.id}.${sourceHash}.error.json`);

    // Cache hit: compiled JS
    try {
      await fs.access(cachedJsPath);
      const cached = await fs.readFile(cachedJsPath, 'utf-8');
      logger.debug(`[Extensions] Cache hit for ${record.id} (${sourceHash})`);
      return { code: cached, sourceHash };
    } catch {
      // Cache miss — continue
    }

    // Cache hit: previous compilation error
    try {
      await fs.access(cachedErrorPath);
      const cachedError = JSON.parse(await fs.readFile(cachedErrorPath, 'utf-8')) as CompilationError;
      logger.debug(`[Extensions] Cached error for ${record.id} (${sourceHash})`);
      return { error: cachedError, sourceHash };
    } catch {
      // Cache miss — compile
    }

    // Compile with esbuild
    try {
      const result = await build({
        entryPoints: [entryPath],
        bundle: true,
        format: 'esm',
        platform: 'browser',
        target: 'es2022',
        external: ['react', 'react-dom', '@dorkos/extension-api'],
        write: false,
        minify: false,
        sourcemap: 'inline',
        logLevel: 'silent',
      });

      const code = result.outputFiles?.[0]?.text ?? '';

      // Bundle size warning
      const sizeKb = Buffer.byteLength(code, 'utf-8') / 1024;
      if (sizeKb > BUNDLE_SIZE_WARNING_KB) {
        logger.warn(
          `[Extensions] Bundle for ${record.id} is ${sizeKb.toFixed(0)}KB (exceeds ${BUNDLE_SIZE_WARNING_KB}KB guideline)`
        );
      }

      // Write to cache, delete any stale error
      await fs.writeFile(cachedJsPath, code, 'utf-8');
      try { await fs.unlink(cachedErrorPath); } catch { /* no stale error */ }

      logger.info(`[Extensions] Compiled ${record.id} (${sizeKb.toFixed(1)}KB)`);
      return { code, sourceHash };
    } catch (err) {
      const esbuildErr = err as { errors?: Array<{ text: string; location?: { file: string; line: number; column: number } }> };
      const compilationError: CompilationError = {
        code: 'compilation_failed',
        message: `Compilation failed for ${record.id}`,
        errors: esbuildErr.errors?.map((e) => ({
          text: e.text,
          location: e.location ? { file: e.location.file, line: e.location.line, column: e.location.column } : undefined,
        })) ?? [{ text: err instanceof Error ? err.message : 'Unknown compilation error' }],
      };

      // Write error to cache
      await fs.writeFile(cachedErrorPath, JSON.stringify(compilationError, null, 2), 'utf-8');

      logger.error(`[Extensions] Compilation failed for ${record.id}: ${compilationError.errors[0]?.text}`);
      return { error: compilationError, sourceHash };
    }
  }

  /**
   * Read a cached bundle by extension ID and source hash.
   * Used by the bundle serving endpoint.
   */
  async readBundle(extId: string, sourceHash: string): Promise<string | null> {
    const cachedPath = path.join(this.cacheDir, `${extId}.${sourceHash}.js`);
    try {
      return await fs.readFile(cachedPath, 'utf-8');
    } catch {
      return null;
    }
  }

  /**
   * Clean stale cache entries not accessed in 7+ days.
   * Called on server startup.
   */
  async cleanStaleCache(): Promise<number> {
    const SEVEN_DAYS_MS = 7 * 24 * 60 * 60 * 1000;
    const now = Date.now();
    let cleaned = 0;

    try {
      await fs.access(this.cacheDir);
    } catch {
      return 0; // Cache dir doesn't exist yet
    }

    const entries = await fs.readdir(this.cacheDir);
    for (const entry of entries) {
      const filePath = path.join(this.cacheDir, entry);
      try {
        const stat = await fs.stat(filePath);
        if (now - stat.atimeMs > SEVEN_DAYS_MS) {
          await fs.unlink(filePath);
          cleaned++;
        }
      } catch {
        // Skip files we can't stat
      }
    }

    if (cleaned > 0) {
      logger.info(`[Extensions] Cleaned ${cleaned} stale cache entries`);
    }
    return cleaned;
  }

  /** Compute SHA-256 content hash (first 16 hex chars). */
  private computeSourceHash(source: string): string {
    return createHash('sha256').update(source).digest('hex').slice(0, 16);
  }

  /** Ensure the cache directory exists. */
  private async ensureCacheDir(): Promise<void> {
    await fs.mkdir(this.cacheDir, { recursive: true });
  }
}
```

