## Factory Implementation

```typescript
/**
 * Construct a per-extension API object.
 *
 * Every register* call is tracked in the cleanups array. On deactivation,
 * all cleanups are called automatically (Obsidian cleanup model).
 *
 * @param extId - Extension ID from the manifest
 * @param deps - Host primitives injected by the loader
 * @returns The API object and the collected cleanup functions
 */
export function createExtensionAPI(
  extId: string,
  deps: ExtensionAPIDeps
): { api: ExtensionAPI; cleanups: Array<() => void> } {
  const cleanups: Array<() => void> = [];

  const api: ExtensionAPI = {
    id: extId,

    registerComponent(slot, id, component, options) {
      const contribution = adaptToContribution(slot, `${extId}:${id}`, component, options);
      const unsub = deps.registry.register(slot, contribution);
      cleanups.push(unsub);
      return unsub;
    },

    registerCommand(id, label, callback, options) {
      const contribution: CommandPaletteContribution = {
        id: `${extId}:${id}`,
        label,
        icon: options?.icon ?? 'puzzle',
        action: `ext:${extId}:${id}`,
        category: 'feature',
        shortcut: options?.shortcut,
      };
      const unsub = deps.registry.register('command-palette.items', contribution);
      cleanups.push(unsub);
      deps.registerCommandHandler(`ext:${extId}:${id}`, callback);
      return unsub;
    },

    registerDialog(id, component) {
      // Register the dialog in the dialog slot with open state management
      let isOpen = false;
      const dialogId = `${extId}:${id}`;

      const contribution = {
        id: dialogId,
        component: component,
        openStateKey: `ext-dialog:${dialogId}`,
      };
      const unsub = deps.registry.register('dialog', contribution);
      cleanups.push(unsub);

      return {
        open: () => { isOpen = true; },
        close: () => { isOpen = false; },
      };
    },

    registerSettingsTab(id, label, component) {
      const contribution = {
        id: `${extId}:${id}`,
        label,
        icon: undefined, // Extensions don't provide LucideIcon instances
        component,
      };
      const unsub = deps.registry.register('settings.tabs', contribution);
      cleanups.push(unsub);
      return unsub;
    },

    executeCommand(command: UiCommand) {
      executeUiCommand(deps.dispatcherContext, command);
    },

    openCanvas(content: UiCanvasContent) {
      executeUiCommand(deps.dispatcherContext, {
        action: 'open_canvas',
        content,
      });
    },

    navigate(path: string) {
      deps.navigate({ to: path });
    },

    getState(): ExtensionReadableState {
      const store = deps.appStore.getState();
      return {
        currentCwd: store.activeCwd ?? null,
        activeSessionId: store.activeSessionId ?? null,
        agentId: store.activeAgentId ?? null,
      };
    },

    subscribe(selector, callback) {
      const unsub = deps.appStore.subscribe((state: any) => {
        const projected: ExtensionReadableState = {
          currentCwd: state.activeCwd ?? null,
          activeSessionId: state.activeSessionId ?? null,
          agentId: state.activeAgentId ?? null,
        };
        return selector(projected);
      }, callback);
      cleanups.push(unsub);
      return unsub;
    },

    async loadData<T>() {
      const res = await fetch(`/api/extensions/${extId}/data`);
      if (res.status === 204) return null;
      return res.json() as Promise<T>;
    },

    async saveData<T>(data: T) {
      await fetch(`/api/extensions/${extId}/data`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });
    },

    notify(message, options) {
      const type = options?.type ?? 'info';
      toast[type === 'error' ? 'error' : type === 'success' ? 'success' : 'info'](message);
    },

    isSlotAvailable(slot) {
      return deps.availableSlots.has(slot);
    },
  };

  return { api, cleanups };
}

/**
 * Adapt a generic component + options to the Phase 2 registry's contribution shape.
 * Different slots have different contribution interfaces.
 */
function adaptToContribution(
  slot: ExtensionPointId,
  id: string,
  component: React.ComponentType,
  options?: { priority?: number }
): any {
  const base = { id, priority: options?.priority ?? 50 };

  switch (slot) {
    case 'dashboard.sections':
      return { ...base, component };
    case 'sidebar.tabs':
      return { ...base, component, label: id, icon: undefined };
