## File: `apps/client/src/layers/features/extensions/model/extension-loader.ts`

## Implementation

```typescript
import type { ExtensionRecordPublic, ExtensionModule } from '@dorkos/extension-api';
import { createExtensionAPI, type ExtensionAPIDeps } from './extension-api-factory.js';
import type { LoadedExtension } from './types.js';

/** Fetch the extension list from the server. */
async function fetchExtensions(): Promise<ExtensionRecordPublic[]> {
  const res = await fetch('/api/extensions');
  if (!res.ok) {
    console.error('[extensions] Failed to fetch extension list:', res.status);
    return [];
  }
  return res.json();
}

export class ExtensionLoader {
  private loaded: Map<string, LoadedExtension> = new Map();
  private deps: ExtensionAPIDeps;

  constructor(deps: ExtensionAPIDeps) {
    this.deps = deps;
  }

  /**
   * Initialize: fetch extension list, import compiled bundles, activate.
   *
   * @returns Array of all discovered extensions and the loaded extensions map
   */
  async initialize(): Promise<{
    extensions: ExtensionRecordPublic[];
    loaded: Map<string, LoadedExtension>;
  }> {
    const extensions = await fetchExtensions();

    // Filter to compiled + bundleReady extensions
    const ready = extensions.filter(
      (ext) => ext.status === 'compiled' && ext.bundleReady
    );

    if (ready.length === 0) {
      console.log('[extensions] No extensions to load');
      return { extensions, loaded: this.loaded };
    }

    // Load bundles in parallel
    const loadResults = await Promise.all(
      ready.map(async (rec) => {
        try {
          const module = (await import(
            /* @vite-ignore */ `/api/extensions/${rec.id}/bundle`
          )) as ExtensionModule;
          return { rec, module, error: null };
        } catch (err) {
          console.error(`[extensions] Failed to import ${rec.id}:`, err);
          return { rec, module: null, error: err };
        }
      })
    );

    // Activate each loaded module
    const activated: string[] = [];
    for (const { rec, module, error } of loadResults) {
      if (!module || error) {
        // Report load failure to server
        try {
          await this.reportStatus(rec.id, 'activate_error', String(error));
        } catch { /* best-effort */ }
        continue;
      }

      try {
        const { api, cleanups } = createExtensionAPI(rec.id, this.deps);
        const deactivateFn = module.activate(api);

        const loaded: LoadedExtension = {
          id: rec.id,
          manifest: rec.manifest,
          module,
          api,
          cleanups,
          deactivate: typeof deactivateFn === 'function' ? deactivateFn : undefined,
        };

        this.loaded.set(rec.id, loaded);
        activated.push(`${rec.manifest.name} v${rec.manifest.version}`);

        // Report activation success to server
        try {
          await this.reportStatus(rec.id, 'active');
        } catch { /* best-effort */ }
      } catch (err) {
        console.error(`[extensions] Failed to activate ${rec.id}:`, err);
        try {
          await this.reportStatus(
            rec.id,
            'activate_error',
            err instanceof Error ? err.message : 'Unknown activation error'
          );
        } catch { /* best-effort */ }
      }
    }

    if (activated.length > 0) {
      console.log(`[extensions] Activated: ${activated.join(', ')}`);
    }

    return { extensions, loaded: this.loaded };
  }

  /**
   * Deactivate all loaded extensions: call deactivate functions, then all cleanups.
   */
  deactivateAll(): void {
    for (const [id, ext] of this.loaded) {
      try {
        ext.deactivate?.();
      } catch (err) {
        console.error(`[extensions] Error calling deactivate for ${id}:`, err);
      }

      for (const cleanup of ext.cleanups) {
        try {
          cleanup();
        } catch (err) {
          console.error(`[extensions] Error in cleanup for ${id}:`, err);
        }
      }
    }

    this.loaded.clear();
  }

  /** Get all currently loaded extensions. */
  getLoaded(): Map<string, LoadedExtension> {
    return this.loaded;
  }

  /** Report extension status back to the server. */
  private async reportStatus(
    id: string,
    status: 'active' | 'activate_error',
    error?: string
  ): Promise<void> {
    // POST to enable endpoint already sets compiled status.
    // For activation status, the server's ExtensionManager.reportActivated/reportActivateError
    // can be called via a lightweight endpoint or the status can be inferred.
    // For v1, status reporting is best-effort via console logging.
    if (status === 'active') {
      console.log(`[extensions] Reported active: ${id}`);
    } else {
      console.warn(`[extensions] Reported activate_error for ${id}: ${error}`);
    }
  }
}
```

