import { createContext, useContext, useEffect, useState, type ReactNode } from 'react';
import type { ExtensionRecordPublic } from '@dorkos/extension-api';
import type { LoadedExtension } from './types.js';
import { ExtensionLoader } from './extension-loader.js';
import type { ExtensionAPIDeps } from './extension-api-factory.js';

/** Context value exposed to the app tree. */
export interface ExtensionContextValue {
  /** All discovered extensions (from server). */
  extensions: ExtensionRecordPublic[];
  /** Currently loaded & activated extensions. */
  loaded: Map<string, LoadedExtension>;
  /** Whether the initial extension load is complete. */
  ready: boolean;
}

const ExtensionContext = createContext<ExtensionContextValue>({
  extensions: [],
  loaded: new Map(),
  ready: false,
});

/**
 * Hook to access the extension system context.
 */
export function useExtensions(): ExtensionContextValue {
  return useContext(ExtensionContext);
}

interface ExtensionProviderProps {
  deps: ExtensionAPIDeps;
  children: ReactNode;
}

/**
 * Provider that loads third-party extensions on mount.
 *
 * Placement in main.tsx:
 *   QueryClientProvider
 *     → TransportProvider
 *       → ExtensionProvider        ← HERE
 *         → PasscodeGateWrapper
 *           → RouterProvider
 *
 * Built-in registrations (initializeExtensions) remain synchronous.
 * Third-party extensions load asynchronously after initial render.
 */
export function ExtensionProvider({ deps, children }: ExtensionProviderProps) {
  const [state, setState] = useState<ExtensionContextValue>({
    extensions: [],
    loaded: new Map(),
    ready: false,
  });

  useEffect(() => {
    const loader = new ExtensionLoader(deps);

    loader.initialize().then(({ extensions, loaded }) => {
      setState({ extensions, loaded, ready: true });
    }).catch((err) => {
      console.error('[extensions] Failed to initialize:', err);
      setState((prev) => ({ ...prev, ready: true }));
    });

    return () => {
      loader.deactivateAll();
    };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps -- deps is stable (constructed once)

  return (
    <ExtensionContext.Provider value={state}>
      {children}
    </ExtensionContext.Provider>
  );
}
```

