import type { ExtensionRecordPublic } from '@dorkos/extension-api';
import { Switch, Badge } from '@/layers/shared/ui';
import { AlertTriangle, XCircle, Puzzle } from 'lucide-react';
import { cn } from '@/layers/shared/lib';

interface ExtensionCardProps {
  extension: ExtensionRecordPublic;
  onToggle: (id: string, enabled: boolean) => void;
  isToggling: boolean;
}

/** Per-extension card in the Extensions settings tab. */
export function ExtensionCard({ extension, onToggle, isToggling }: ExtensionCardProps) {
  const { manifest, status, scope, error } = extension;
  const isEnabled = !['disabled', 'discovered', 'incompatible', 'invalid'].includes(status);
  const isIncompatible = status === 'incompatible';
  const isInvalid = status === 'invalid';
  const hasError = status === 'compile_error' || status === 'activate_error';
  const canToggle = !isIncompatible && !isInvalid;

  return (
    <div
      data-slot="extension-card"
      className={cn(
        'rounded-xl border bg-card p-4',
        hasError && 'border-warning/50',
        isIncompatible && 'border-muted opacity-75'
      )}
    >
      <div className="flex items-start justify-between gap-4">
        <div className="flex-1 space-y-1">
          <div className="flex items-center gap-2">
            {/* Status icon */}
            {hasError && <AlertTriangle className="size-4 text-warning" />}
            {isIncompatible && <XCircle className="size-4 text-muted-foreground" />}
            {!hasError && !isIncompatible && <Puzzle className="size-4 text-muted-foreground" />}

            {/* Name + version */}
            <span className="font-medium">{manifest.name}</span>
            <span className="text-sm text-muted-foreground">v{manifest.version}</span>
          </div>

          {/* Description */}
          {manifest.description && (
            <p className="text-sm text-muted-foreground">{manifest.description}</p>
          )}

          {/* Error message */}
          {hasError && error && (
            <p className="text-sm text-warning">
              {status === 'compile_error' ? 'Compilation error: ' : 'Activation failed: '}
              {error.message}
            </p>
          )}

          {/* Incompatible message */}
          {isIncompatible && manifest.minHostVersion && (
            <p className="text-sm text-muted-foreground">
              Requires DorkOS {'>'}= {manifest.minHostVersion}
            </p>
          )}

          {/* Metadata row */}
          <div className="flex items-center gap-2 text-xs text-muted-foreground">
            <Badge variant="outline" className="text-xs">
              {scope}
            </Badge>
            {manifest.author && <span>Author: {manifest.author}</span>}
          </div>
        </div>

        {/* Enable/disable toggle */}
        <div className="pt-1">
          <Switch
            checked={isEnabled}
            onCheckedChange={(checked) => onToggle(extension.id, checked)}
            disabled={!canToggle || isToggling}
            aria-label={`${isEnabled ? 'Disable' : 'Enable'} ${manifest.name}`}
          />
        </div>
      </div>
    </div>
  );
}
