## File: `ExtensionsSettingsTab.tsx`

```typescript
import { useState } from 'react';
import { RefreshCw } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/layers/shared/ui';
import { useExtensions } from '../model/extension-context.js';
import { ExtensionCard } from './ExtensionCard.js';
import type { ExtensionRecordPublic } from '@dorkos/extension-api';

/** Extensions tab in the Settings dialog. */
export function ExtensionsSettingsTab() {
  const { extensions: initialExtensions } = useExtensions();
  const [extensions, setExtensions] = useState<ExtensionRecordPublic[]>(initialExtensions);
  const [togglingIds, setTogglingIds] = useState<Set<string>>(new Set());
  const [isReloading, setIsReloading] = useState(false);

  async function handleToggle(id: string, enabled: boolean) {
    setTogglingIds((prev) => new Set(prev).add(id));

    try {
      const endpoint = enabled ? 'enable' : 'disable';
      const res = await fetch(`/api/extensions/${id}/${endpoint}`, { method: 'POST' });

      if (!res.ok) {
        const body = await res.json().catch(() => ({ error: 'Unknown error' }));
        toast.error(`Failed to ${endpoint} extension: ${body.error}`);
        return;
      }

      const data = await res.json();

      // Update the local extensions list
      setExtensions((prev) =>
        prev.map((ext) => (ext.id === id ? data.extension : ext))
      );

      if (data.reloadRequired) {
        toast.info('Extension changes require a page reload', {
          action: {
            label: 'Reload now',
            onClick: () => location.reload(),
          },
        });
      }
    } catch (err) {
      toast.error(`Failed to update extension: ${err instanceof Error ? err.message : 'Unknown error'}`);
    } finally {
      setTogglingIds((prev) => {
        const next = new Set(prev);
        next.delete(id);
        return next;
      });
    }
  }

  async function handleReload() {
    setIsReloading(true);
    try {
      const res = await fetch('/api/extensions/reload', { method: 'POST' });
      if (!res.ok) {
        toast.error('Failed to reload extensions');
        return;
      }
      const updated = await res.json();
      setExtensions(updated);
      toast.success(`Reloaded ${updated.length} extension(s)`);
    } catch (err) {
      toast.error('Failed to reload extensions');
    } finally {
      setIsReloading(false);
    }
  }

  return (
    <div className="space-y-4">
      {extensions.length === 0 ? (
        <div className="py-8 text-center text-muted-foreground">
          <p>No extensions installed.</p>
          <p className="mt-1 text-sm">
            Place extensions in <code className="rounded bg-muted px-1">~/.dork/extensions/</code>{' '}
            or <code className="rounded bg-muted px-1">.dork/extensions/</code>
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {extensions.map((ext) => (
            <ExtensionCard
              key={ext.id}
              extension={ext}
              onToggle={handleToggle}
              isToggling={togglingIds.has(ext.id)}
            />
          ))}
        </div>
      )}

      <div className="flex justify-end">
        <Button
          variant="outline"
          size="sm"
          onClick={handleReload}
          disabled={isReloading}
        >
          <RefreshCw className={cn('mr-2 size-4', isReloading && 'animate-spin')} />
          Reload Extensions
        </Button>
      </div>
    </div>
  );
}
```

